1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	interface MainItemSpec {
56	  insuranceValue: number;
57	  basePremium: number;
58	}
59	
60	const MAIN_ITEMS: Record<string, MainItemSpec> = {
61	  sword: { insuranceValue: 1000, basePremium: 100 },
62	  amulet: { insuranceValue: 600, basePremium: 60 },
63	  staff: { insuranceValue: 800, basePremium: 80 },
64	  potion: { insuranceValue: 400, basePremium: 40 },
65	};
66	
67	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
68	
69	const COMPONENT_INSURANCE = 250;
70	const COMPONENT_PREMIUM = 25;
71	const BLOCK_PREMIUM = 60;
72	const DEDUCTIBLE = 100;
73	const PROCESSING_FEE = 5;
74	
75	function isMainItem(type: string): boolean {
76	  return type in MAIN_ITEMS;
77	}
78	
79	function isComponent(type: string): boolean {
80	  return COMPONENT_TYPES.has(type);
81	}
82	
83	function validateItemTypes(items: Item[]): void {
84	  for (const item of items) {
85	    if (!isMainItem(item.type) && !isComponent(item.type)) {
86	      throw new Error(`Unknown item type: ${item.type}`);
87	    }
88	  }
89	}
90	
91	interface PolicyItem {
92	  item: Item;
93	  insuranceValue: number;
94	  basePremium: number;
95	}
96	
97	interface Policy {
98	  items: PolicyItem[];
99	  insuranceSum: number;
100	  cap: number;
101	  remainingCap: number;
102	}
103	
104	function itemInsuranceValue(item: Item): number {
105	  if (isMainItem(item.type)) {
106	    return MAIN_ITEMS[item.type].insuranceValue;
107	  }
108	  return COMPONENT_INSURANCE;
109	}
110	
111	function itemBasePremium(item: Item): number {
112	  if (isMainItem(item.type)) {
113	    return MAIN_ITEMS[item.type].basePremium;
114	  }
115	  return COMPONENT_PREMIUM;
116	}
117	
118	function itemSurchargeMultiplier(item: Item): number {
119	  let mult = 1;
120	  if (item.cursed) mult += 0.5;
121	  if ((item.enchantment ?? 0) >= 5) mult += 0.3;
122	  return mult;
123	}
124	
125	function computeComponentsBasePremium(components: Item[]): number {
126	  const byType = new Map<string, number>();
127	  for (const c of components) {
128	    byType.set(c.type, (byType.get(c.type) ?? 0) + 1);
129	  }
130	  let total = 0;
131	  for (const count of byType.values()) {
132	    if (count === 3) {
133	      total += BLOCK_PREMIUM;
134	    } else {
135	      total += count * COMPONENT_PREMIUM;
136	    }
137	  }
138	  return total;
139	}
140	
141	function computePolicyItems(items: Item[]): PolicyItem[] {
142	  return items.map((item) => ({
143	    item,
144	    insuranceValue: itemInsuranceValue(item),
145	    basePremium: itemBasePremium(item),
146	  }));
147	}
148	
149	function computePolicy(items: Item[]): Policy {
150	  const policyItems = computePolicyItems(items);
151	  const insuranceSum = policyItems.reduce((sum, pi) => sum + pi.insuranceValue, 0);
152	  const cap = insuranceSum * 2;
153	  return {
154	    items: policyItems,
155	    insuranceSum,
156	    cap,
157	    remainingCap: cap,
158	  };
159	}
160	
161	interface PremiumContext {
162	  yearsWithMHPCO: number;
163	  isFirstContract: boolean;
164	}
165	
166	function computePremium(items: Item[], ctx: PremiumContext): number {
167	  validateItemTypes(items);
168	
169	  if (items.length === 0) {
170	    return PROCESSING_FEE;
171	  }
172	
173	  const mainItems = items.filter((i) => isMainItem(i.type));
174	  const components = items.filter((i) => isComponent(i.type));
175	
176	  let policyBase = 0;
177	
178	  // Main items: base × per-item surcharges
179	  for (const item of mainItems) {
180	    const base = itemBasePremium(item);
181	    const surcharged = base * itemSurchargeMultiplier(item);
182	    policyBase += surcharged;
183	  }
184	
185	  // Components: block discount applied, then per-item surcharges proportionally?
186	  // Per the spec, components don't typically have enchantment/curse, but if they did,
187	  // surcharges apply to the item's base premium. With block, a component's effective
188	  // base premium is shared. We'll keep it simple: apply surcharges only to components,
189	  // but block pricing applies to total premium of like components.
190	  // Actually, simpler: compute block-discounted base for components, ignore curse/enchant
191	  // on components (spec doesn't show any examples of cursed runes).
192	  policyBase += computeComponentsBasePremium(components);
193	
194	  // Policy-wide modifiers: applied to plain policy base (sum of item base premiums).
195	  // Per clarification: each item in a quote is treated as a first insurance regardless
196	  // of customer history, so the 10% always applies.
197	  let policyMultiplier = 0.1; // first insurance always applies
198	  if (ctx.yearsWithMHPCO >= 2) policyMultiplier -= 0.2;
199	  if (!ctx.isFirstContract) policyMultiplier -= 0.15;
200	
201	  // Compute policy base premium (sum of item bases, no per-item surcharges)
202	  // For modifier purposes per spec: "policy-wide modifiers ... apply to the policy base premium (the sum of all item base premiums)"
203	  let plainPolicyBase = 0;
204	  for (const item of mainItems) plainPolicyBase += itemBasePremium(item);
205	  plainPolicyBase += computeComponentsBasePremium(components);
206	
207	  const policyWideAdjustment = plainPolicyBase * policyMultiplier;
208	
209	  const beforeFee = policyBase + policyWideAdjustment;
210	  const total = beforeFee + PROCESSING_FEE;
211	
212	  return Math.ceil(total);
213	}
214	
215	function findMatchingItem(policy: Policy, itemType: string, used: Set<number>): PolicyItem | null {
216	  for (let i = 0; i < policy.items.length; i++) {
217	    if (used.has(i)) continue;
218	    if (policy.items[i].item.type === itemType) {
219	      used.add(i);
220	      return policy.items[i];
221	    }
222	  }
223	  return null;
224	}
225	
226	function computeItemPayout(policyItem: PolicyItem, damageAmount: number): number {
227	  const item = policyItem.item;
228	  const isDragon = item.material === "dragon";
229	  const isHighEnchant = (item.enchantment ?? 0) >= 8;
230	
231	  let reimbursement: number;
232	  if (isHighEnchant) {
233	    reimbursement = damageAmount * 0.5;
234	  } else if (isDragon) {
235	    reimbursement = damageAmount;
236	  } else {
237	    reimbursement = damageAmount;
238	  }
239	
240	  const afterDeductible = reimbursement - DEDUCTIBLE;
241	  return Math.max(0, afterDeductible);
242	}
243	
244	function processClaim(policy: Policy, incident: Incident): ClaimResult {
245	  if (incident.damages.some((d) => d.amount < 0)) {
246	    throw new Error("Damage amount cannot be negative");
247	  }
248	
249	  const used = new Set<number>();
250	  let totalPayout = 0;
251	
252	  for (const damage of incident.damages) {
253	    const matched = findMatchingItem(policy, damage.itemType, used);
254	    if (!matched) {
255	      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
256	    }
257	    totalPayout += computeItemPayout(matched, damage.amount);
258	  }
259	
260	  // Round down (in MHPCO's favor)
261	  let payout = Math.floor(totalPayout);
262	
263	  // Apply remaining cap
264	  if (payout > policy.remainingCap) {
265	    payout = policy.remainingCap;
266	  }
267	
268	  policy.remainingCap -= payout;
269	
270	  return {
271	    payout,
272	    remainingCap: policy.remainingCap,
273	  };
274	}
275	
276	export function runScenario(scenario: Scenario): ScenarioResult {
277	  const results: StepResult[] = [];
278	  const policies = new Map<number, Policy>();
279	  let quoteCount = 0;
280	
281	  for (let i = 0; i < scenario.steps.length; i++) {
282	    const step = scenario.steps[i];
283	
284	    if (step.op === "quote") {
285	      validateItemTypes(step.items);
286	      const isFirstContract = quoteCount === 0;
287	      const premium = computePremium(step.items, {
288	        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
289	        isFirstContract,
290	      });
291	      const policy = computePolicy(step.items);
292	      policies.set(i, policy);
293	      results.push({ premium });
294	      quoteCount++;
295	    } else {
296	      const policy = policies.get(step.policy);
297	      if (!policy) {
298	        throw new Error(`Claim references unknown policy: ${step.policy}`);
299	      }
300	      const result = processClaim(policy, step.incident);
301	      results.push(result);
302	    }
303	  }
304	
305	  return { results };
306	}
