3	async function readStdin(): Promise<string> {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) {
6	    chunks.push(chunk as Buffer);
7	  }
8	  return Buffer.concat(chunks).toString("utf8");
9	}
10	
11	async function main(): Promise<void> {
12	  try {
13	    const input = await readStdin();
14	    const scenario = JSON.parse(input) as Scenario;
15	    const result = runScenario(scenario);
16	    process.stdout.write(JSON.stringify(result));
17	  } catch (err) {
18	    const msg = err instanceof Error ? err.message : String(err);
19	    process.stderr.write(msg + "\n");
20	    process.exit(1);
21	  }
22	}
23	
24	main();
