4	function quote(items: any[], years = 0, prior: any[] = []): number {
5	  const scenario: Scenario = {
6	    customer: { yearsWithMHPCO: years },
7	    steps: [...prior.map((it) => ({ op: "quote" as const, items: it })), { op: "quote", items }],
8	  };
9	  const result = runScenario(scenario);
10	  const last = result.results[result.results.length - 1] as { premium: number };
11	  return last.premium;
12	}
13	
14	function claim(items: any[], damages: any[], years = 0): { payout: number; remainingCap: number } {
15	  const scenario: Scenario = {
16	    customer: { yearsWithMHPCO: years },
17	    steps: [
18	      { op: "quote", items },
19	      { op: "claim", policy: 0, incident: { cause: "test", damages } },
20	    ],
21	  };
22	  const result = runScenario(scenario);
23	  return result.results[1] as { payout: number; remainingCap: number };
24	}
